// Extract message text from Brevo webhook payload
const body = $input.first().json.body || $input.first().json;
const messageText = (body.message || body.text || body.content || '').toLowerCase().trim();
const senderPhone = body.from || body.phone || body.sender || '';
const senderName = body.name || body.sender_name || 'there';

// FAQ keyword matching
let faqMatch = 'default';
let response = '';

if (messageText.includes('book') || messageText.includes('how')) {
  faqMatch = 'booking';
  response = `Hi ${senderName}! To book a session, click the booking link your coach shared. Select your session, enter your details, and confirm. You can pay online via Stripe or pay cash at the session.`;
} else if (messageText.includes('session') || messageText.includes('available')) {
  faqMatch = 'availability';
  response = `Available sessions change weekly. Click your booking link to see all open sessions with dates, times, and prices.`;
} else if (messageText.includes('cancel')) {
  faqMatch = 'cancellation';
  response = `To cancel a booking, reply with your full name and booking details. Your coach will process the cancellation.`;
} else if (messageText.includes('price') || messageText.includes('cost') || messageText.includes('much')) {
  faqMatch = 'pricing';
  response = `Session prices vary by type and level. Check your booking link to see prices for each available session.`;
} else if (messageText.includes('bring') || messageText.includes('wear') || messageText.includes('need')) {
  faqMatch = 'preparation';
  response = `For most sessions, bring: sports shoes, water, and weather-appropriate clothes. Check your session details for anything specific.`;
} else if (messageText.includes('time') || messageText.includes('when') || messageText.includes('start')) {
  faqMatch = 'timing';
  response = `Session times are listed on the booking page and in your confirmation email. Reply with your name if you need the exact time for your session.`;
} else {
  faqMatch = 'default';
  response = `Thanks for your message! For bookings, use the booking link your coach shared. For other questions, your coach will respond as soon as possible.`;
}

return [{
  json: {
    messageText,
    senderPhone,
    senderName,
    faqMatch,
    response,
    timestamp: new Date().toISOString()
  }
}];
